     1→import type { Finding, ProcessResult, ReviewResult, ReviewThreadDetail, ThreadComment } from "../types.js";
     2→import { getTracer, withSpan, type Logger } from "./observability.js";
     3→
     4→export const REVIEW_COMMENT_HEADER = "# Vibereq Review";
     5→
     6→export const SEVERITY_EMOJI: Record<string, string> = {
     7→  critical: ":x:",
     8→  major: ":warning:",
     9→  minor: ":grey_question:",
    10→  info: ":information_source:",
    11→};
    12→
    13→export const STATUS_EMOJI: Record<string, string> = {
    14→  fulfilled: ":white_check_mark:",
    15→  partial: ":yellow_circle:",
    16→  missing: ":red_circle:",
    17→  violation: ":x:",
    18→};
    19→
    20→interface ReviewComment {
    21→  path: string;
    22→  line: number;
    23→  start_line?: number;
    24→  body: string;
    25→}
    26→
    27→async function runCommand(cmd: string[]): Promise<ProcessResult> {
    28→  const proc = Bun.spawn(cmd, { stdout: "pipe", stderr: "pipe" });
    29→  const stdout = await new Response(proc.stdout).text();
    30→  const stderr = await new Response(proc.stderr).text();
    31→  const exitCode = await proc.exited;
    32→  return { stdout, stderr, exitCode };
    33→}
    34→
    35→export async function getCurrentPR(): Promise<number | null> {
    36→  const tracer = getTracer();
    37→
    38→  return withSpan(tracer, "getCurrentPR", async () => {
    39→    // GitHub Actions sets GITHUB_EVENT_PATH with the event payload
    40→    if (process.env.GITHUB_EVENT_NAME === "pull_request") {
    41→      const eventPath = process.env.GITHUB_EVENT_PATH;
    42→      if (eventPath) {
    43→        try {
    44→          const file = Bun.file(eventPath);
    45→          const event = await file.json();
    46→          const prNumber = event?.pull_request?.number;
    47→          if (typeof prNumber === "number") {
    48→            return prNumber;
    49→          }
    50→        } catch {
    51→          // Fall through to gh CLI
    52→        }
    53→      }
    54→    }
    55→
    56→    // Try to get PR from gh CLI
    57→    const result = await runCommand([
    58→      "gh",
    59→      "pr",
    60→      "view",
    61→      "--json",
    62→      "number",
    63→      "-q",
    64→      ".number",
    65→    ]);
    66→    if (result.exitCode === 0 && /^\d+$/.test(result.stdout.trim())) {
    67→      return parseInt(result.stdout.trim(), 10);
    68→    }
    69→
    70→    return null;
    71→  });
    72→}
    73→
    74→export async function getDiffLines(
    75→  baseBranch = "main"
    76→): Promise<Map<string, Set<number>>> {
    77→  const tracer = getTracer();
    78→
    79→  return withSpan(tracer, "getDiffLines", async () => {
    80→    const result = await runCommand([
    81→      "git",
    82→      "diff",
    83→      `${baseBranch}...HEAD`,
    84→      "--unified=0",
    85→    ]);
    86→    if (result.exitCode !== 0) {
    87→      return new Map();
    88→    }
    89→
    90→    const diffLines = new Map<string, Set<number>>();
    91→    let currentFile: string | null = null;
    92→
    93→    for (const line of result.stdout.split("\n")) {
    94→      // Match file header: +++ b/path/to/file.ts
    95→      if (line.startsWith("+++ b/")) {
    96→        currentFile = line.slice(6);
    97→        diffLines.set(currentFile, new Set());
    98→      }
    99→      // Match hunk header: @@ -old,count +new,count @@
   100→      else if (line.startsWith("@@") && currentFile) {
   101→        const match = /\+(\d+)(?:,(\d+))?/.exec(line);
   102→        if (match) {
   103→          const start = parseInt(match[1], 10);
   104→          const count = match[2] ? parseInt(match[2], 10) : 1;
   105→          const fileLines = diffLines.get(currentFile)!;
   106→          for (let i = start; i < start + count; i++) {
   107→            fileLines.add(i);
   108→          }
   109→        }
   110→      }
   111→    }
   112→
   113→    return diffLines;
   114→  }, { baseBranch });
   115→}
   116→
   117→function formatFindingForDiffComment(finding: Finding): string {
   118→  const severityEmoji = SEVERITY_EMOJI[finding.severity] || "";
   119→  const statusEmoji = STATUS_EMOJI[finding.status] || "";
   120→
   121→  return [
   122→    `${severityEmoji} **${finding.requirement}**`,
   123→    `Status: ${statusEmoji} ${finding.status}`,
   124→    "",
   125→    finding.details,
   126→  ].join("\n");
   127→}
   128→
   129→async function getCommitSha(prNumber: number, logger?: Logger): Promise<string | null> {
   130→  const tracer = getTracer();
   131→  return withSpan(tracer, "getCommitSha", async () => {
   132→    const shaResult = await runCommand([
   133→      "gh",
   134→      "pr",
   135→      "view",
   136→      String(prNumber),
   137→      "--json",
   138→      "headRefOid",
   139→      "-q",
   140→      ".headRefOid",
   141→    ]);
   142→    if (shaResult.exitCode !== 0) {
   143→      logger?.error("Failed to get PR head commit", { prNumber, stderr: shaResult.stderr });
   144→      return null;
   145→    }
   146→    return shaResult.stdout.trim();
   147→  }, { prNumber });
   148→}
   149→
   150→function buildReviewComment(finding: Finding): ReviewComment | null {
   151→  if (!finding.location) return null;
   152→
   153→  const body = formatFindingForDiffComment(finding);
   154→  const comment: ReviewComment = {
   155→    path: finding.location.file,
   156→    line: finding.location.endLine ?? finding.location.line,
   157→    body,
   158→  };
   159→
   160→  if (
   161→    finding.location.endLine &&
   162→    finding.location.endLine !== finding.location.line
   163→  ) {
   164→    comment.start_line = finding.location.line;
   165→  }
   166→
   167→  return comment;
   168→}
   169→
   170→async function resolveReviewThread(threadId: string): Promise<boolean> {
   171→  const query = `
   172→    mutation ResolveThread($threadId: ID!) {
   173→      resolveReviewThread(input: {threadId: $threadId}) {
   174→        thread {
   175→          id
   176→        }
   177→      }
   178→    }
   179→  `;
   180→
   181→  const result = await runCommand([
   182→    "gh",
   183→    "api",
   184→    "graphql",
   185→    "-f",
   186→    `query=${query}`,
   187→    "-f",
   188→    `threadId=${threadId}`,
   189→  ]);
   190→
   191→  return result.exitCode === 0;
   192→}
   193→
   194→interface VibereqReview {
   195→  id: number;
   196→  body: string;
   197→  htmlUrl: string;
   198→}
   199→
   200→/**
   201→ * Get all Vibereq reviews on a PR (identified by the REVIEW_COMMENT_HEADER)
   202→ */
   203→async function getVibereqReviews(prNumber: number): Promise<VibereqReview[]> {
   204→  const result = await runCommand([
   205→    "gh",
   206→    "api",
   207→    `/repos/{owner}/{repo}/pulls/${prNumber}/reviews`,
   208→    "--paginate",
   209→  ]);
   210→
   211→  if (result.exitCode !== 0) return [];
   212→
   213→  try {
   214→    const reviews = JSON.parse(result.stdout);
   215→    return reviews
   216→      .filter((r: { body: string }) => r.body?.includes(REVIEW_COMMENT_HEADER))
   217→      .filter((r: { body: string }) => !r.body?.includes("<details>"))
   218→      .map((r: { id: number; body: string; html_url: string }) => ({
   219→        id: r.id,
   220→        body: r.body,
   221→        htmlUrl: r.html_url,
   222→      }));
   223→  } catch {
   224→    return [];
   225→  }
   226→}
   227→
   228→/**
   229→ * Archive a review by collapsing its body with a link to the new review
   230→ */
   231→async function archiveReview(
   232→  prNumber: number,
   233→  reviewId: number,
   234→  originalBody: string,
   235→  newReviewUrl: string
   236→): Promise<boolean> {
   237→  const collapsedBody = `<details>
   238→<summary>[review superseded by <a href="${newReviewUrl}">new review</a>]</summary>
   239→
   240→${originalBody}
   241→</details>`;
   242→
   243→  const tempFile = `/tmp/vibx-archive-${Date.now()}.json`;
   244→  await Bun.write(tempFile, JSON.stringify({ body: collapsedBody }));
   245→
   246→  const result = await runCommand([
   247→    "gh",
   248→    "api",
   249→    "-X",
   250→    "PUT",
   251→    `/repos/{owner}/{repo}/pulls/${prNumber}/reviews/${reviewId}`,
   252→    "--input",
   253→    tempFile,
   254→  ]);
   255→
   256→  // Clean up temp file
   257→  try {
   258→    if (await Bun.file(tempFile).exists()) {
   259→      await runCommand(["rm", tempFile]);
   260→    }
   261→  } catch {
   262→    // Ignore cleanup errors
   263→  }
   264→
   265→  return result.exitCode === 0;
   266→}
   267→
   268→/**
   269→ * Archive all previous Vibereq reviews on a PR
   270→ * @param excludeReviewId - The ID of the new review to exclude from archiving
   271→ */
   272→export async function archivePreviousReviews(
   273→  prNumber: number,
   274→  newReviewUrl: string,
   275→  excludeReviewId: number,
   276→  logger?: Logger
   277→): Promise<void> {
   278→  const tracer = getTracer();
   279→
   280→  return withSpan(tracer, "archivePreviousReviews", async () => {
   281→    const allReviews = await getVibereqReviews(prNumber);
   282→    const previousReviews = allReviews.filter(r => r.id !== excludeReviewId);
   283→
   284→    if (previousReviews.length === 0) {
   285→      logger?.debug("No previous Vibereq reviews to archive");
   286→      return;
   287→    }
   288→
   289→    logger?.info("Archiving previous reviews", { count: previousReviews.length });
   290→    console.log(`Archiving ${previousReviews.length} previous review(s)...`);
   291→
   292→    // Get unresolved review threads only from previous Vibereq reviews
   293→    const previousReviewIds = previousReviews.map(r => r.id);
   294→    const threads = await getReviewThreads(prNumber, previousReviewIds);
   295→
   296→    // Resolve threads from previous reviews only
   297→    for (const thread of threads) {
   298→      const resolved = await resolveReviewThread(thread.id);
   299→      if (resolved) {
   300→        logger?.debug("Resolved thread", { path: thread.path, line: thread.line });
   301→      }
   302→    }
   303→
   304→    if (threads.length > 0) {
   305→      console.log(`  Resolved ${threads.length} comment thread(s)`);
   306→    }
   307→
   308→    // Collapse each previous review
   309→    for (const review of previousReviews) {
   310→      const archived = await archiveReview(prNumber, review.id, review.body, newReviewUrl);
   311→      if (archived) {
   312→        logger?.debug("Archived review", { reviewId: review.id });
   313→        console.log(`  Archived review #${review.id}`);
   314→      } else {
   315→        logger?.warn("Failed to archive review", { reviewId: review.id });
   316→      }
   317→    }
   318→  }, { prNumber });
   319→}
   320→
   321→async function getReviewThreads(
   322→  prNumber: number,
   323→  filterReviewIds?: number[]
   324→): Promise<Array<{ id: string; path: string; line: number }>> {
   325→  const query = `
   326→    query GetReviewThreads($owner: String!, $repo: String!, $pr: Int!) {
   327→      repository(owner: $owner, name: $repo) {
   328→        pullRequest(number: $pr) {
   329→          reviewThreads(last: 100) {
   330→            nodes {
   331→              id
   332→              isResolved
   333→              path
   334→              line
   335→              comments(first: 1) {
   336→                nodes {
   337→                  pullRequestReview {
   338→                    databaseId
   339→                  }
   340→                }
   341→              }
   342→            }
   343→          }
   344→        }
   345→      }
   346→    }
   347→  `;
   348→
   349→  // Get owner and repo from gh
   350→  const repoResult = await runCommand([
   351→    "gh",
   352→    "repo",
   353→    "view",
   354→    "--json",
   355→    "owner,name",
   356→  ]);
   357→  if (repoResult.exitCode !== 0) return [];
   358→
   359→  const repoInfo = JSON.parse(repoResult.stdout);
   360→  const owner = repoInfo.owner.login;
   361→  const repo = repoInfo.name;
   362→
   363→  const result = await runCommand([
   364→    "gh",
   365→    "api",
   366→    "graphql",
   367→    "-f",
   368→    `query=${query}`,
   369→    "-f",
   370→    `owner=${owner}`,
   371→    "-f",
   372→    `repo=${repo}`,
   373→    "-F",
   374→    `pr=${prNumber}`,
   375→  ]);
   376→
   377→  if (result.exitCode !== 0) return [];
   378→
   379→  try {
   380→    const data = JSON.parse(result.stdout);
   381→    const threads = data.data.repository.pullRequest.reviewThreads.nodes;
   382→    return threads
   383→      .filter((t: { isResolved: boolean }) => !t.isResolved)
   384→      .filter((t: { comments: { nodes: Array<{ pullRequestReview?: { databaseId?: number } }> } }) => {
   385→        if (!filterReviewIds || filterReviewIds.length === 0) return true;
   386→        const reviewId = t.comments.nodes[0]?.pullRequestReview?.databaseId;
   387→        return reviewId != null && filterReviewIds.includes(reviewId);
   388→      })
   389→      .map((t: { id: string; path: string; line: number }) => ({
   390→        id: t.id,
   391→        path: t.path,
   392→        line: t.line,
   393→      }));
   394→  } catch {
   395→    return [];
   396→  }
   397→}
