   399→export async function submitReview(
   400→  prNumber: number,
   401→  result: ReviewResult,
   402→  diffFindings: Finding[],
   403→  generalFindings: Finding[],
   404→  dryRun = false,
   405→  logger?: Logger
   406→): Promise<{ success: boolean; failedFindings: Finding[]; reviewUrl?: string }> {
   407→  const tracer = getTracer();
   408→
   409→  return withSpan(tracer, "submitReview", async () => {
   410→    const failedFindings: Finding[] = [];
   411→
   412→    // Build review comments from diff findings
   413→    const comments: ReviewComment[] = [];
   414→    const fulfilledComments: Array<{ path: string; line: number }> = [];
   415→
   416→    for (const finding of diffFindings) {
   417→      const comment = buildReviewComment(finding);
   418→      if (comment) {
   419→        comments.push(comment);
   420→        if (finding.status === "fulfilled") {
   421→          fulfilledComments.push({ path: comment.path, line: comment.line });
   422→        }
   423→      } else {
   424→        failedFindings.push(finding);
   425→      }
   426→    }
   427→
   428→    // Build review body from general findings and summary
   429→    const reviewBody = formatReviewBody(result, generalFindings);
   430→
   431→    if (dryRun) {
   432→      logger?.info("Dry run - would submit review", { commentCount: comments.length });
   433→      console.log(`[DRY RUN] Would submit review with ${comments.length} diff comment(s)`);
   434→      for (const comment of comments) {
   435→        console.log(`  - ${comment.path}:${comment.line}`);
   436→      }
   437→      console.log(`[DRY RUN] Review body preview: ${reviewBody.slice(0, 200)}...`);
   438→      if (fulfilledComments.length > 0) {
   439→        console.log(`[DRY RUN] Would resolve ${fulfilledComments.length} fulfilled comment(s)`);
   440→      }
   441→      console.log(`[DRY RUN] Would archive previous Vibereq reviews`);
   442→      return { success: true, failedFindings };
   443→    }
   444→
   445→    const commitSha = await getCommitSha(prNumber, logger);
   446→    if (!commitSha) {
