   480→    } catch {
   481→      // Ignore cleanup errors
   482→    }
   483→
   484→    if (createResult.exitCode !== 0) {
   485→      logger?.error("Failed to create review", { prNumber, stderr: createResult.stderr });
   486→      return { success: false, failedFindings: [...diffFindings, ...generalFindings] };
   487→    }
   488→
   489→    // Extract the new review ID and URL from the response
   490→    let reviewUrl: string | undefined;
   491→    let reviewId: number | undefined;
   492→    try {
   493→      const reviewData = JSON.parse(createResult.stdout);
   494→      reviewUrl = reviewData.html_url;
   495→      reviewId = reviewData.id;
   496→    } catch {
   497→      logger?.warn("Could not extract review data from response");
   498→    }
   499→
   500→    logger?.info("Created review", { prNumber, commentCount: comments.length, reviewUrl, reviewId });
   501→    console.log(`Created review with ${comments.length} diff comment(s)`);
   502→
   503→    // Archive previous Vibereq reviews (exclude the one we just created)
   504→    if (reviewUrl && reviewId) {
   505→      await archivePreviousReviews(prNumber, reviewUrl, reviewId, logger);
   506→    }
   507→
   508→    // Resolve fulfilled comments from the NEW review
   509→    if (fulfilledComments.length > 0) {
   510→      console.log(`Resolving ${fulfilledComments.length} fulfilled comment(s)...`);
   511→      const threads = await getReviewThreads(prNumber);
   512→
   513→      for (const fulfilled of fulfilledComments) {
   514→        const thread = threads.find(
   515→          (t) => t.path === fulfilled.path && t.line === fulfilled.line
   516→        );
   517→        if (thread) {
   518→          const resolved = await resolveReviewThread(thread.id);
   519→          if (resolved) {
   520→            logger?.debug("Resolved thread", { path: fulfilled.path, line: fulfilled.line });
   521→            console.log(`  Resolved: ${fulfilled.path}:${fulfilled.line}`);
   522→          }
   523→        }
   524→      }
   525→    }
   526→
   527→    return { success: true, failedFindings, reviewUrl };
   528→  }, { prNumber, dryRun });
   529→}
