   536→        ? ":x:"
   537→        : ":warning:";
   538→
   539→  const lines = [
   540→    `${REVIEW_COMMENT_HEADER}`,
   541→    "",
   542→    `## ${result.reviewerName}`,
   543→    `**Overall Status:** ${statusEmoji} ${result.status.toUpperCase()}`,
   544→  ];
   545→
   546→  if (result.summary) {
   547→    lines.push("", result.summary);
   548→  }
   549→
   550→  if (generalFindings.length > 0) {
